import 'package:flutter/material.dart';\nimport 'screens/auth_screen.dart';\nimport 'artist_login_screen.dart';\nimport 'admin_login_screen.dart';\nimport 'artist_dashboard_screen.dart';\nimport 'admin_dashboard_screen.dart';\nimport 'dashboard_entry_screen.dart';\n\nvoid main() {\n  runApp(const EchoVaultApp());\n}\n\nclass EchoVaultApp extends StatelessWidget {\n  const EchoVaultApp({super.key});\n\n  @override\n  Widget build(BuildContext context) {\n    return MaterialApp(\n      title: 'EchoVault',\n      debugShowCheckedModeBanner: false,\n      theme: ThemeData.dark().copyWith(\n        primaryColor: Colors.purpleAccent,\n        scaffoldBackgroundColor: const Color(0xFF0F0C29),\n      ),\n      initialRoute: '/dashboard-entry',\n      routes: {\n        '/auth': (context) => const AuthScreen(),\n        '/dashboard-entry': (context) => const DashboardEntryScreen(),\n        '/artist-login': (context) => const ArtistLoginScreen(),\n        '/admin-login': (context) => const AdminLoginScreen(),\n        '/artist-dashboard': (context) => const ArtistDashboardScreen(),\n        '/admin-dashboard': (context) => const AdminDashboardScreen(),\n        '/home': (context) => const Scaffold(body: Center(child: Text('Home Screen'))),\n      },\n    );\n  }\n}
